import { useNavigate } from 'react-router-dom';
import Button from '../components/Button';
import MultiCardVideoContainer from "../components/MultiCardVideoContainer";
import { videos_creamyland } from '../constants';
import "../styles/Home.css";


  function Home(){

    const navigate = useNavigate();
    
    return <div className='home-app'>
    <MultiCardVideoContainer videos={videos_creamyland} />
    <Button
          buttonLabel={"game"}
          onClick={() => navigate('/game')}
        />
    </div>
  }

  export default Home;
